let additionalData = additionalServices.value;
let dataToBeAdded = [];
additionalData.forEach((val) => {
  let bool = false;
  tempData.forEach((temp) => {
    if(temp.serviceName === val.serviceName) {
      bool = true;
    }
  })
  if(!bool) {
    dataToBeAdded.push(val);
  }
})
